label "correspond à" as label6
label "pratique" as label7

Membre -- Comité : label1
Membre -- Comité : label2
Comité -- Activité : label3
Participant -- Epreuve : label4
Spécialité -- Epreuve : label5
Membre -- Inscription : label6
Amateur -- Epreuve : label7

@enduml
